public void testAppendFixedWidthPadRight_TruncateLongerString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight("hello", 3, '-');
    assertEquals("hel", sb.toString());
}

public void testAppendFixedWidthPadRight_PadShorterString() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight("hi", 5, '*');
    assertEquals("hi***", sb.toString());
}

public void testAppendFixedWidthPadRight_ExactWidth() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight("test", 4, '-');
    assertEquals("test", sb.toString());
}

public void testAppendFixedWidthPadRight_NullObject() {
    StrBuilder sb = new StrBuilder();
    sb.appendFixedWidthPadRight(null, 6, '-');
    String result = sb.toString();
    assertTrue(result.endsWith("--") || result.endsWith("-"));
    assertEquals(6, result.length());
}
